+                starvation_max_boost: 0.08,
+                thrash_flip_threshold: 2,
+                thrash_penalty: 0.3,
+                ..GovernorConfig::default()
+            },
+            extraction_config: PlannerExtractionConfig::default(),
+        }
+    }
+}
